mapper.select:
SELECT id, script_id, script_version_id, parent_step_id, step_type, name, sort_no,
       request_method, request_url, request_config, assertion_config, extractor_config,
       enabled, created_time, updated_time, created_by, updated_by, deleted
FROM step_definition
WHERE script_id = #{scriptId}
  AND script_version_id = #{versionId}
  AND id = #{id}
  AND deleted = 0

